import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as e,c as p,a as s,b as n,d as c,e as r}from"./app-20457886.js";const l={},u=s("h1",{id:"json介绍",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#json介绍","aria-hidden":"true"},"#"),n(" Json介绍")],-1),i=s("p",null,"JSON是JavaScript Object Notation的缩写，意思是JavaScript 对象表示法",-1),d=s("p",null,"是存储和交换文本信息的语法。类似 XML，不过它比 XML 更小、更快，更易解析",-1),k={href:"http://www.json.org/json-zh.html",target:"_blank",rel:"noopener noreferrer"},g=r(`<p>JSON(JavaScript Object Notation) 是一种<strong>轻量级的数据交换格式</strong>。 易于人阅读和编写。同时也易于机器解析和生成。 它基于JavaScript Programming Language, Standard ECMA-262 3rd Edition - December 1999的一个子集。 JSON采用<strong>完全独立于语言的文本格式</strong>，但是也使用了类似于C语言家族的习惯（包括C, C++, C#, Java, JavaScript, Perl, Python等）。 这些特性使JSON成为理想的数据交换语言。</p><h3 id="json-语法规则" tabindex="-1"><a class="header-anchor" href="#json-语法规则" aria-hidden="true">#</a> JSON 语法规则</h3><p>JSON建构于两种结构：</p><blockquote><p>&quot;名称/值&quot;对的集合 (键值对)</p></blockquote><p>不同的语言中，它被理解为对象（object）、纪录（record）、结构（struct）、字典（dictionary）、哈希表（hash table）、有键列表（keyed list）、或者关联</p><p>对象是一个无序的**&#39;名称/值&#39;对<strong>集合。一个对象以</strong>​**<code>{</code><strong>​</strong>（左括号）开始，<strong>​</strong><code>}</code><strong>​</strong>（右括号）结束。每个<strong>名称</strong>后跟一个<strong>​</strong><code>:</code><strong>​</strong>（冒号）；<strong>&#39;名称/值&#39;对</strong> 对之间使用<code>,</code>（逗号）分隔</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span><span class="token property">&quot;name&quot;</span><span class="token operator">:</span><span class="token string">&quot;张三&quot;</span><span class="token punctuation">,</span><span class="token property">&quot;age&quot;</span><span class="token operator">:</span><span class="token number">23</span><span class="token punctuation">,</span><span class="token property">&quot;salary&quot;</span><span class="token operator">:</span><span class="token number">12.3</span><span class="token punctuation">,</span><span class="token property">&quot;sex&quot;</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p>数组</p></blockquote><p>值的有序列表（An ordered list of values）。在大部分语言中，它被理解为数组（array）。</p><p>数组是值（value）的有序集合。一个数组以<code>[</code>（左中括号）开始，<code>]</code>（右中括号）结束。值之间使用<code>,</code>（逗号）分隔</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">[</span><span class="token string">&quot;hello&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;boy&quot;</span><span class="token punctuation">,</span><span class="token number">12</span><span class="token punctuation">,</span><span class="token number">12</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">,</span><span class="token boolean">true</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>值（value）可以是双引号括起来的字符串（<code>string</code>）、数值(<code>number</code>)、<code>true</code>、<code>false</code>、 <code>null</code>、对象（<code>object</code>）或者数组（<code>array</code>）。这些结构可以嵌套。</p><h3 id="json-与-js-对象的关系" tabindex="-1"><a class="header-anchor" href="#json-与-js-对象的关系" aria-hidden="true">#</a> JSON 与 JS 对象的关系</h3><p>很多人搞不清楚 JSON 和 JS 对象的关系，甚至连谁是谁都不清楚。其实，可以这么理解：<br><strong>JSON 是 JS 对象的字符串表示法，它使用文本表示一个 JS 对象的信息，本质是一个字符串。</strong><br> 如</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token literal-property property">a</span><span class="token operator">:</span> <span class="token string">&#39;Hello&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">b</span><span class="token operator">:</span> <span class="token string">&#39;World&#39;</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token comment">//这是一个对象，注意键名也是可以使用引号包裹的</span>

<span class="token keyword">var</span> json <span class="token operator">=</span> <span class="token string">&#39;{&quot;a&quot;: &quot;Hello&quot;, &quot;b&quot;: &quot;World&quot;}&#39;</span><span class="token punctuation">;</span> <span class="token comment">//这是一个 JSON 字符串，本质是一个字符串</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="json-和-js-对象互转" tabindex="-1"><a class="header-anchor" href="#json-和-js-对象互转" aria-hidden="true">#</a> JSON 和 JS 对象互转</h3><p>要实现从JSON字符串转换为JS对象，使用 JSON.parse() 方法：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> obj <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span><span class="token string">&#39;{&quot;a&quot;: &quot;Hello&quot;, &quot;b&quot;: &quot;World&quot;}&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//结果是 {a: &#39;Hello&#39;, b: &#39;World&#39;}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要实现从JS对象转换为JSON字符串，使用 JSON.stringify() 方法：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> json <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token literal-property property">a</span><span class="token operator">:</span> <span class="token string">&#39;Hello&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">b</span><span class="token operator">:</span> <span class="token string">&#39;World&#39;</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//结果是 &#39;{&quot;a&quot;: &quot;Hello&quot;, &quot;b&quot;: &quot;World&quot;}&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,20);function v(b,m){const a=t("ExternalLinkIcon");return e(),p("div",null,[u,i,d,s("p",null,[n("官网的介绍 "),s("a",k,[n("http://www.json.org/json-zh.html"),c(a)])]),g])}const j=o(l,[["render",v],["__file","Json介绍.html.vue"]]);export{j as default};
